import { Box, Button, Dialog, DialogActions, DialogContent, DialogContentText, DialogTitle, FormHelperText, Icon, MenuItem, TextField } from '@material-ui/core'
import axios from 'axios'
import React, { useState, useEffect } from 'react'
import { useNavigate } from 'react-router-dom'
import Cookies from 'js-cookie'
import { CheckCircleOutlineRounded } from '@material-ui/icons'



export default function EditProfile() {
    const history = useNavigate();

    const id = Cookies.get('idLoggedIn');
    const [passwordDialog, setPasswordDialog] = useState(false);
    const [wrongPassword, setWrongPassword] = useState(false);
    const [userPassword, setUserPassword] = useState('');
    const [success, setSuccess] = useState(false);

    const cancelSubmit = () => {
        setPasswordDialog(false)
    }

    const checkPassword = () => {
        const sendData = {
            password: userPassword,
            id,
            firstName: data.firstName,
            middleName: data.middleName,
            lastName: data.lastName,
            course: data.course,
            college: data.college
        }

        axios.post('https://ursacapi.000webhostapp.com/api/individualUpdateStudent.php', JSON.stringify(sendData))
            .then(response => {
                if (response.data == 'Success') {
                    setSuccess(true);
                } else {
                    setWrongPassword(true)
                }
            })
            .catch(error => console.log(error))
    }

    const handlePasswordChange = (event) => {
        setUserPassword(event.target.value)
    }



    const showStudent = () => {
        const sendData = {
            updateID: id
        }
        axios.post('https://ursacapi.000webhostapp.com/api/getStudentID.php', JSON.stringify(sendData))
            .then(response => {
                setData(response.data[0])
            })
            .catch(err => console.log(err))
    }


    useEffect(() => {
        showStudent();
    }, []);

    const [data, setData] = useState({
        studentID: '',
        firstName: '',
        middleName: '',
        lastName: '',
        college: '',
        course: '',
        password: ''
    })






    const handleChange = (event) => {
        const name = event.target.name;
        const value = event.target.value;

        setData(data => ({ ...data, [name]: value }));
    }




    const handleSubmit = (e) => {
        e.preventDefault();
        setPasswordDialog(true)
    };






    return (

        <Box>

            <center>

                {/* // STUDENT */}
                <div>
                    <form onSubmit={handleSubmit}>

                        <FormHelperText>Student ID</FormHelperText>
                        <TextField placeholder='Student ID' type="text" name='studentID' value={data.studentID} onChange={handleChange} fullWidth disabled />
                        <br /><br />

                        <FormHelperText>First Name</FormHelperText>
                        <TextField variant='outlined' placeholder='First Name' type="text" name='firstName' value={data.firstName} onChange={handleChange} fullWidth />
                        <br /><br />

                        <FormHelperText>Middle Name</FormHelperText>
                        <TextField variant='outlined' placeholder='Middle Name' type="text" name='middleName' value={data.middleName} onChange={handleChange} fullWidth />
                        <br /><br />

                        <FormHelperText>Last Name</FormHelperText>
                        <TextField variant='outlined' placeholder='Last Name' type="text" name='lastName' value={data.lastName} onChange={handleChange} fullWidth />
                        <br /><br />

                        <FormHelperText>College</FormHelperText>
                        <TextField variant='outlined' placeholder='College' type="text" name='college' value={data.college} onChange={handleChange} fullWidth />
                        <br /><br />

                        <FormHelperText>Course</FormHelperText>
                        <TextField variant='outlined' placeholder='Course' type="text" name='course' value={data.course} onChange={handleChange} fullWidth multiline />
                        <br /><br />

                        <FormHelperText>Password</FormHelperText>
                        <TextField variant='outlined' placeholder='Password' type="text" name='password' value={data.password} onChange={handleChange} fullWidth disabled />
                        <br /><br />


                        <Button fullWidth type='submit' name='submit' variant='contained' color='secondary'> Edit Changes </Button>

                    </form>
                </div>
            </center>

            <Dialog
                open={passwordDialog}
                onClose={cancelSubmit}
            >
                {
                    success ?

                        <DialogContent>
                            <DialogContentText>
                                Changes Applied <Icon><CheckCircleOutlineRounded /></Icon>
                            </DialogContentText>
                        </DialogContent>

                        :

                        <Box>
                            <DialogTitle>
                                Enter password to confirm
                            </DialogTitle>

                            <DialogContent>
                                <TextField label='Password' type='password' error={wrongPassword} onChange={() => setWrongPassword(false)} value={userPassword} onChange={handlePasswordChange} fullWidth />
                            </DialogContent>

                            <DialogActions>
                                <Button variant='contained' color='secondary' onClick={checkPassword} >Confirm</Button>
                                <Button variant='outlined' color='secondary' onClick={cancelSubmit} >Cancel</Button>
                            </DialogActions>
                        </Box>
                }



            </Dialog>

        </Box>
    )
}
